={{
(() => {
  const data = $('Generate Idea + Multi-Platform Text (Gemini)').item.json.output;

  const post = data.linkedinPost || '';

  let hashtagsArray = [];

  if (Array.isArray(data.hashtags)) {
    hashtagsArray = data.hashtags;
  } else if (typeof data.hashtags === 'string') {
    hashtagsArray = data.hashtags.split(',').map(h => h.trim());
  }

  const hashtags = hashtagsArray.map(h => '#' + h.replace('#', '')).join(' ');

  return post 
    + '\n\n—\n🔗 Visit: https://gkwebtech.cloud\n\n' 
    + hashtags;
})()
}}
